    public static void processOrder(String orderDataStr, List<Integer> priceList) {  
        String[] split = orderDataStr.split("–"); // splits the string into two parts based on '-' symbol    

       if (split.length != 2){ 
           System.out.println("Invalid Order Data: " + Arrays.toString(split));   
           return;  
        }     

        int productPrice = priceList.get(Integer.parseInt(split[0])); // get the corresponding value from list based on first part of order data 

       if (productPrice == -1){    
            System.out.println("Invalid Product ID: " + split[0]);   
           return;  
        }     

        int quantity = Integer.parseInt(split[1]); // convert the second part into integer  and multiply it with product price to get total order cost    

       if (quantity < 1){    
            System.out.println("Invalid Quantity: " + split[0]+" -> quantity should be greater than zero");   
           return;  
        }     

        int finalPrice = productPrice * quantity ; // calculate the total cost  by multiplying price of a single item with its count    

       System.out.println("Order Price: " +finalPrice);// print out order's result   
           return;  
            }     
}```       
